                                        System.out.println("Fixing generic type mismatch for: " + assignment.toString());
                                        // The fix would involve updating the type to ManagedObject<?>
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        // For a more robust solution, let's create a proper Spoon transformer
        System.out.println("Transformation rule created for fixing SortedMap generic type mismatch in getRegistry() calls");
    }
}

